var e=JSON.parse(`[{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"오래 전, 아홉 대륙을 아우르는 전설이 있었다.","JPN":"大昔、九つの大陸をまとめる伝説があった。","ENG":"A long time ago, there was a legend that was told across the nine continents.","TWN":"這無趣的傳說是這麼說的，很久很久以前，據說9個大陸是合在一起的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"하늘의 선택을 받은 구원자가 나타나 모두를 괴로움에서 구원하리라는, 시시한 전설이.","JPN":"天から選ばれし救世主が現れ、みんなを苦痛から救うというくだらない伝説が。","ENG":"A bland legend that spoke of the arrival of the Savior, appointed by the heavens, who would save everyone from suffering.","TWN":"天選之救贖者出現，將在水深火熱之中的人救贖出來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그는 어두운 시대에 희망을 추구하던 여인 앞에 홀연히 나타나 성녀를 찾아왔다고 하지만…","JPN":"彼は暗き時代の中で希望を求めていた女性の前に忽然と現れ、聖女の力が必要だという。だけど……","ENG":"It is said that he would reveal himself to a woman praying for hope in a dark age and claim that he came searching for the Saintess, but...","TWN":"女孩則是在黑暗的世代中尋求一絲希望，有一天，救贖者突然出現在女孩面前，說是來找聖女的…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"당시 노예였던 내게, 그것은 너무나도 먼 세계의 이야기였다.","JPN":"当時奴隷だった私にとって、それはあまりにも遠い世界の話だった。","ENG":"It was such a distant story, as I was a slave at the time.","TWN":"但對於當時身為奴隸的我而言，這是一個遙不可及的故事。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GRANDPA_MEMORIAL_NULL","text":{"KOREA":"쿨럭. 쿨럭…!","JPN":"ゴホッ。ゴホッ……！","ENG":"*Cough!* *Cough!*","TWN":"咳咳，咳咳…！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"할아버지. 몸은 좀 괜찮으세요?","JPN":"お爺さん。体の具合はどう？","ENG":"Grandfather. Are you okay?","TWN":"爺爺，你還好嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"자요. 주인 녀석 모르게 물을 가져왔어요. 이것 좀 드시고 하세요.","JPN":"はい。主人のやつには内緒で水を持ってきたよ。飲んで。","ENG":"Here. I brought you some water behind the master's back. Please, drink some.","TWN":"這是我從堂主那偷拿來的水，爺爺你喝一點吧。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRANDPA_MEMORIAL_NULL","text":{"KOREA":"고맙구나. 루크야… 쿨럭!","JPN":"ありがとう。ルク……ゴホッ！","ENG":"Thank you, Lucy... *Cough!*","TWN":"謝謝你，露可… 咳咳！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"그러게 몸도 안 좋으신 분이 뭘 또 그렇게 무리하시고 그래요.","JPN":"具合もよくないんだから無理しなきゃいいのに。","ENG":"You know you're unwell. You shouldn't overwork yourself.","TWN":"你身體又不好，幹嘛這樣勉強自己。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"할아버지가 다치면 저희만 힘들어져요. 저는 어제 맞은 데가 아직도 욱신거린다고요.","JPN":"お爺さんが怪我したら私たちが苦労するんだよ。私なんか昨日叩かれたところがまだ痛いんだから。","ENG":"If you hurt yourself, we're the ones who will suffer. It still hurts where I got hit yesterday.","TWN":"爺爺受傷的話，辛苦的只有我們。我昨天挨的那一頓打，到現在還會痛呢。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GRANDPA_MEMORIAL_NULL","text":{"KOREA":"루크야… 넌 이 할애비를 원망하니?","JPN":"ルク……わしを恨んでるかい？","ENG":"Lucy... Do you hate this old man?","TWN":"露可… 你會怨恨爺爺嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GRANDPA_MEMORIAL_NULL","text":{"KOREA":"조금만 참아주려무나. 구원자님께서 곧 우리를 구원해주실… 쿨럭!","JPN":"もう少し我慢しておくれ。救世主様がすぐ、我々を救って……ゴホッ！","ENG":"It won't be much longer. The Savior will come to save– *Cough!*","TWN":"再忍耐一下，救贖者大人很快就會來拯救我們… 咳咳！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"그놈의 구원이니 뭐니…! 이제 제발 정신 좀 차려요!","JPN":"救世だのなんの……！　もういいかげん目を覚ましてよ！","ENG":"Stop it with the Savior gibberish! Please, you have to come to your senses!","TWN":"那所謂的救贖…！我拜託你清醒一點！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L23_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"할아버지도 아시잖아요! 제국에서 정한 구원자는 저희 같은 노예에게 아무런 관심도 없다고요!","JPN":"お爺さんもわかってるでしょ！　帝国が決めた救世主は、私たちみたいな奴隷にはなんの興味もないって！","ENG":"You know that the Savior appointed by the Empire isn't interested in slaves like us!","TWN":"爺爺你也知道！帝國指定的救贖者大人根本就不關心我們這些奴隸！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"그러니까 제발……","JPN":"だから、お願い……","ENG":"So please...","TWN":"所以我拜託你…"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_PAST_NULL","text":{"KOREA":"제발… 정신 좀 차리라고요…….","JPN":"頼むから……目を覚まして……","ENG":"Please... come to your senses...","TWN":"拜託你…醒醒吧…"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"지독하리만큼 편협한 이야기임에도,\\n눈을 감으면 펼쳐지는 광명이 현실의 어둠마저 걷어 내주기 때문일까.","JPN":"何の根拠もない話なのに、目を閉じると広がる光明が現実の闇さえ晴らしてくれるからだろうか。","ENG":"It was such a closed-minded story, but perhaps the brilliant light that shined on him when he closed his eyes chased away the darkness in reality.","TWN":"雖然這是一個狹隘至極的故事，\\n但每當閉上眼睛時，那光明就會展現在眼前，甚至能驅散現實的黑暗。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GRANDPA_MEMORIAL_NULL","text":{"KOREA":"구원자님… 부디…","JPN":"救世主様……どうか……","ENG":"Savior... please...","TWN":"救贖者大人… 求求你…"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRANDPA_MEMORIAL_NULL","text":{"KOREA":"구원… 하소서…….","JPN":"お救い……くださいませ……","ENG":"Save... us...","TWN":"拯救我們吧…"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"그것이 분에 넘친 기대라는 것을 알고 있음에도,\\n할아버지는 죽는 그 순간까지 희망을 놓지 않았다.","JPN":"それが出過ぎた期待であることとわかっていながら、お爺さんは死ぬ間際まで希望を手放さなかった。","ENG":"He knew his hopes were far-fetched, but he did not let them go, even on his deathbed.","TWN":"即使心裡明白這是個不切實際的期待，\\n但爺爺直到死去的那一刻都沒有放棄希望。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"그래.","JPN":"そう。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FIRE_06"},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"기다리기만 해선……","JPN":"待つだけでは……","ENG":"Waiting...","TWN":"光是等待……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"<color=#ff3636>아무것도 바뀌지 않아</color>.","JPN":"<color=#ff3636>何も変わらない</color>。","ENG":"<color=#ff3636>won't get you anywhere</color>.","TWN":"<color=#ff3636>什麼事都不會改變的</color>。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>아르카데나 제국</color> 수도. 센트럴 팰리스.","JPN":"<color=#ffd34c>アルカデナ帝国</color>の首都。セントラルパレス。","ENG":"Central Palace, the capital of the <color=#ffd34c>Empire of Arcadena</color>.","TWN":"<color=#ffd34c>艾爾卡特納帝國</color> 首都 聖特羅貝里斯"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"subtitle","speaker":null,"text":{"KOREA":"성녀 루크레시아. <color=#ffd34c>정기 도시 순찰</color>.","JPN":"聖女ルクレシア。<color=#ffd34c>定期都市巡回</color>。","ENG":"Saintess Lucrecia. <color=#ffd34c>Regular city patrol</color>.","TWN":"聖女 露可蕾西亞 <color=#ffd34c>定期巡視城市</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_A","text":{"KOREA":"황태자여. 구원자의 검을 받아보거라!","JPN":"皇太子よ。救世主の剣を受け止めてみろ！","ENG":"Crown prince, face the sword of the Savior!","TWN":"皇太子，看我救贖者大人之劍的厲害！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MOVEMENT_12"},{"id":"L46_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_B","text":{"KOREA":"좋다. 내 친히 네놈을 상대해주마!","JPN":"よかろう。直々に貴様の相手をしてやろう！","ENG":"Very well. I shall generously accept that challenge!","TWN":"很好，我就親自和你過二招！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"에휴. 남자아이들은 틈만 나면 쌈박질이야.","JPN":"もう。男の子って暇さえあればチャンバラごっこしてるんだから。","ENG":"Ugh. Why do boys like to fight so much?","TWN":"男生都這樣，動不動就打來打去的。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"성녀님이 칭찬해주신 뒤로 계속 저런 상태예요. 진짜 쪽팔리지도 않는지 원.","JPN":"聖女様に褒められた後からずっとあんな状態なんです。本当に恥ずかしくないのかな。","ENG":"They've been doing that ever since you complimented them, Saintess. It's embarrassing.","TWN":"自從被聖女誇獎後就一直是那副德性，丟不丟臉？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그건 부활의 지팡이를 만든 건가요?","JPN":"それは、復活の杖を作ったのですか？","ENG":"Is that the Staff of Resurrection you made there?","TWN":"那是用復活之杖做的嗎？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"아, 알아보시나요? 저 이거 엄청 열심히 만들었어요!","JPN":"あ、わかりますか？　私、これ本当に頑張って作ったんですよ！","ENG":"Oh, can you recognize it? I put a lot of effort into making this!","TWN":"是聖女，你有看出來嗎？這是我花很多心血做出來的！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L6_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"저는 성녀님처럼 되는 게 꿈이거든요.","JPN":"私は聖女様みたいになるのが夢なんです。","ENG":"I want to be like you when I grow up.","TWN":"我的夢想是想跟聖女一樣。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"저처럼… 말인가요?","JPN":"私みたいに……ですか？","ENG":"Like... me?","TWN":"你想…像我一樣？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"네! 성녀님은 엄청 예쁘고, 성격도 좋고, 심지어 강하기까지 하잖아요!","JPN":"はい！　聖女様はすごく綺麗だし、性格もいいし、しかも強いんでしょ？","ENG":"Yes! You're super pretty, you're super nice, and you're super strong!","TWN":"是！聖女不只長得超漂亮，又很善良，甚至還很會打架！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"마왕 같은 건 한 주먹거리도 안 돼요! 그렇죠, 성녀님?","JPN":"魔王なんかは一発でやっつけられますよね！　ね？　聖女様！","ENG":"That Demon Lord won't stand a chance against you! Right, Your Holiness?","TWN":"你一拳就可以打倒魔王對吧！聖女？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L10_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"글쎄요. 제가 그렇게 대단한 사람인지는 잘 모르겠네요.","JPN":"どうでしょうか。私がそんなにすごい人かどうか。","ENG":"Well, I'm not sure if I'm all that.","TWN":"是嗎？我自己都不知道我有這麼厲害。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"성녀님도 참. 겸손하기까지 하셔라!","JPN":"聖女様ったら。ご謙遜を！","ENG":"You're super humble too!","TWN":"聖女還很謙卑呢！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"그런데 성녀님. 그… 제가 소문으로 들은 게 있는데, 한 가지만 여쭤봐도 괜찮을까요?","JPN":"でも、聖女様。あの、私……噂を聞いたのですが、一つだけ聞いてもいいですか？","ENG":"Oh, Your Holiness. I... heard a rumor, and I wanted to ask you something.","TWN":"那個，聖女…我有聽到一個流言，可以問你一下嗎？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"소문? 어떤 걸 말하시는 거죠?","JPN":"噂？　何でしょう？","ENG":"Rumor? What are you referring to?","TWN":"流言？什麼流言？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"성녀님과 구원자님은… 그게.","JPN":"聖女様と救世主様は……その。","ENG":"Are you and the Savior... Um.","TWN":"就是聖女和救贖者大人大人…"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"사귀시는 건가요?","JPN":"付き合ってるんですか？","ENG":"Girlfriend and boyfriend?","TWN":"是在交往嗎？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_01"},{"id":"L20_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"대체 어디서 그런 소문을 들으셨는지 모르겠군요.","JPN":"いったいどこからそのような噂を聞いたのでしょうか。","ENG":"How did you even come across such an absurd rumor?","TWN":"你是從哪裡聽說的？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L21_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"별건 아니고, 애들끼리 소꿉놀이할 때 매번 두 분이 결혼하면서 끝나거든요.","JPN":"別に大したことじゃないんですけど、友達とおままごとをすると、いつも二人が結婚して終わるんです。","ENG":"It's just, when the kids play house, it always ends with you two getting married.","TWN":"沒有啦，就是小朋友在玩扮家家酒的時候，每次都是一個演聖女，一個演救贖者大人大人。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"그게 애들 사이에서 퍼지다 보니, 진짜인지 아닌지 궁금해하는 아이들이 많아요.","JPN":"それがみんなの間で広がって、本当かどうか気になってる子が結構いて。","ENG":"And it spread among the kids, so there's a lot of them who are curious if it's real.","TWN":"這件事傳開來後，大家都很好奇。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…구원자님과 저는 전장에 함께 서는 동료입니다.","JPN":"……救世主様と私は、共に戦場に立つ仲間です。","ENG":"...The Savior and I are comrades who stand on the battlefield together.","TWN":"…救贖者大人大人和我只是戰場上並肩作戰的夥伴。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"등을 맡길 수 있는 동료에게 유대감이 형성되는 것은 당연하지요.","JPN":"背中を預けられる仲間に、絆が生まれるのは当たり前のことです。","ENG":"It is natural that trusted comrades form bonds with each other.","TWN":"對於生死相交的夥伴來說，感情好是自然的。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"하지만 여러분이 생각하시는 그런 관계는 아닙니다.","JPN":"ですが、皆さんが思うそのような関係ではありません。","ENG":"But it is not the type of relationship you are thinking of.","TWN":"但我們不是大家所想的那種關係。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"성녀로서의 결혼은 교리로서 금지하고 있기도 하고요.","JPN":"聖女の結婚は教理で禁止されていますし。","ENG":"Not to mention that marriage is forbidden for a Saintess.","TWN":"而且按照教義，聖女是不可以結婚的。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"에이~ 아쉬워라.","JPN":"ええ～残念。","ENG":"Awww. That's a shame.","TWN":"蛤～好可惜喔。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"……아직은.","JPN":"……今は。","ENG":"...At least for now.","TWN":"……目前是這樣。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L33_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"네? 뭐라고요?","JPN":"え？　何か言いましたか？","ENG":"Pardon? What did you say?","TWN":"蛤？你說什麼？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"아무것도 아닙니다.","JPN":"何でもありません。","ENG":"Nothing.","TWN":"沒什麼。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"그나저나 성녀의 사랑 이야기라니. 이런 이야기에 관심이 많으신가 보네요.","JPN":"ところで聖女の恋物語だなんて。こういった話にとても興味があるようですね。","ENG":"But a Saintess' love story? It seems like you are interested in that kind of tales.","TWN":"倒是你們，竟然在八卦聖女的感情，你們對這種事很有興趣是吧？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"네! 이제 곧 왕성에서 무도회가 열리잖아요.","JPN":"はい！　もうすぐ王城で舞踏会が開かれるでしょう？","ENG":"Yup! And there's going to be a ball in the royal palace soon, right?","TWN":"那當然！皇宮就快舉辦舞會咧。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L38_1","type":"dialog","speaker":"CHILDREN_MEMORIAL_NULL_C","text":{"KOREA":"성녀님 정도 되시는 분이 누구에게 춤 권유를 할지 궁금했어요!","JPN":"聖女様のような方は、誰にダンスを申し込むのか気になって！","ENG":"I was curious to see whom a Saintess would ask to dance with!","TWN":"好好奇聖女會和什麼樣的人跳舞！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHILDREN_MEMORIAL_NULL_C","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L40_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"무도회?","JPN":"舞踏会？","ENG":"A ball?","TWN":"舞會？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};